 1	import React, { FC } from 'react';
 2	
 3	import { IoK8sApiNetworkingV1NetworkPolicy } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 4	import { Grid, GridItem, PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
 5	import Loading from '@utils/components/Loading/Loading';
 6	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 7	
 8	import NetworkPolicyDetailsEgress from './components/NetworkPolicyDetailsEgress';
 9	import NetworkPolicyDetailsIngress from './components/NetworkPolicyDetailsIngress';
10	import NetworkPolicyDetailsMetadata from './components/NetworkPolicyDetailsMetadata';
11	
12	type NetworkPolicyDetailsProps = {
13	  obj: IoK8sApiNetworkingV1NetworkPolicy;
14	};
15	
16	const NetworkPolicyDetails: FC<NetworkPolicyDetailsProps> = ({ obj: networkPolicy }) => {
17	  const { t } = useNetworkingTranslation();
18	
19	  if (!networkPolicy) return <Loading />;
20	
21	  return (
22	    <>
23	      <PageSection variant={PageSectionVariants.light}>
24	        <Title headingLevel="h2">{t('{{kind}} details', { kind: networkPolicy.kind })}</Title>
25	        <Grid span={6}>
26	          <GridItem>
27	            <NetworkPolicyDetailsMetadata networkPolicy={networkPolicy} />
28	          </GridItem>
29	        </Grid>
30	      </PageSection>
31	      <PageSection variant={PageSectionVariants.light}>
32	        <NetworkPolicyDetailsIngress networkPolicy={networkPolicy} />
33	      </PageSection>
34	      <PageSection variant={PageSectionVariants.light}>
35	        <NetworkPolicyDetailsEgress networkPolicy={networkPolicy} />
36	      </PageSection>
37	    </>
38	  );
39	};
40	
41	export default NetworkPolicyDetails;

